const session = $('Query Session').first().json;
const logs = $input.all().map(item => item.json);

// Calculate overall percentage from logs
let overallPercentage = 0;
let currentStep = 'queued';

// Find the maximum percentage across all log entries
const maxLogPercentage = logs.reduce((max, l) => Math.max(max, l.percentage || 0), 0);

if (session.status === 'completed' || maxLogPercentage >= 100) {
  overallPercentage = 100;
  currentStep = 'completed';
} else if (session.status === 'failed') {
  currentStep = 'failed';
  overallPercentage = maxLogPercentage;
} else {
  // In progress: get highest percentage seen
  overallPercentage = maxLogPercentage;
  // Get the latest log for step name
  const latestByTime = [...logs].sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];
  if (latestByTime) {
    currentStep = latestByTime.step_name || 'processing';
  }
}

// Group logs by q_id to show per-question progress
const questionProgress = {};
for (const log of logs) {
  if (log.question_id && !questionProgress[log.question_id]) {
    questionProgress[log.question_id] = {
      questionId: log.question_id,
      status: log.status,
      step: log.step_name,
      percentage: (overallPercentage >= 100 || log.step_name === 'completed') ? 100 : (log.percentage || 0),
      lastUpdate: log.created_at
    };
  }
}

// Estimate completion time
let estimatedCompletionAt = null;
if (session.status === 'processing' && overallPercentage > 0 && overallPercentage < 100) {
  const elapsed = new Date() - new Date(session.started_at);
  const estimatedTotal = (elapsed / overallPercentage) * 100;
  estimatedCompletionAt = new Date(new Date(session.started_at).getTime() + estimatedTotal);
}

return [{
  json: {
    sessionId: session.session_id,
    jobId: session.job_id,
    status: overallPercentage >= 100 ? 'completed' : session.status,
    domainId: session.domain_id,
    overallPercentage: Math.min(Math.round(overallPercentage), 100),
    totalQuestions: session.total_questions,
    answeredQuestions: session.answered_questions,
    currentStep: currentStep,
    startedAt: session.started_at,
    completedAt: session.completed_at,
    estimatedCompletionAt: estimatedCompletionAt,
    overallScore: session.overall_compliance_score,
    questionProgress: Object.values(questionProgress)
  }
}];
